INITIAL_STATE = "1,2,3,4,6,108,109,110,111,112,113,114,115,116,117,140,141,142,143,144,145,146,147,148,149,161,262,267,273,279,284,289,299,306,312,316,317,318,319,320,321,322,323,324,325,326,327,328,329,330,331,332,333,334,335,336,337,338,339,340,341,342,343,344,345,346,347,348,349,350,351,352,353,354,355,356,357,358,359,360,361,362,363,364,365,366,367,432,435,438,441,444,447,450,453,455,457,459,461,463,465,467,469,471,473,475,477,479,481"

def execute_action(rule_id, lxm):
    lexbuf = lxm
    if rule_id == "#1":
        return None # skip whitespaces
    if rule_id == "#2":
        return None # skip whitespaces
    if rule_id == "#3":
        val = lxm.replace('"', '\\"')
        return f"FLOAT_LIT(\"{val}\")"
    if rule_id == "#4":
        val = lxm.replace('"', '\\"')
        return f"INT_LIT(\"{val}\")"
    if rule_id == "#5":
        val = lxm.replace('"', '\\"')
        return f"STRING_LIT(\"{val}\")"
    if rule_id == "#6":
        val = lxm.replace('"', '\\"')
        return f"BOOL_LIT(\"{val}\")"
    if rule_id == "#7":
        val = lxm.replace('"', '\\"')
        return f"BOOL_LIT(\"{val}\")"
    if rule_id == "#8":
        return "KW_MACRO"
    if rule_id == "#9":
        return "KW_EMIT"
    if rule_id == "#10":
        return "KW_WHEN"
    if rule_id == "#11":
        return "KW_OTHERWISE"
    if rule_id == "#12":
        return "KW_REPEAT"
    if rule_id == "#13":
        return "KW_UNTIL"
    if rule_id == "#14":
        return "KW_LET"
    if rule_id == "#15":
        val = lxm.replace('"', '\\"')
        return f"IDENT(\"{val}\")"
    if rule_id == "#16":
        return "ASSIGN"
    if rule_id == "#17":
        return "EQ"
    if rule_id == "#18":
        return "NEQ"
    if rule_id == "#19":
        return "LEQ"
    if rule_id == "#20":
        return "GEQ"
    if rule_id == "#21":
        return "AND"
    if rule_id == "#22":
        return "OR"
    if rule_id == "#23":
        return "PLUS"
    if rule_id == "#24":
        return "MINUS"
    if rule_id == "#25":
        return "TIMES"
    if rule_id == "#26":
        return "DIV"
    if rule_id == "#27":
        return "MOD"
    if rule_id == "#28":
        return "LT"
    if rule_id == "#29":
        return "GT"
    if rule_id == "#30":
        return "NOT"
    if rule_id == "#31":
        return "LPAREN"
    if rule_id == "#32":
        return "RPAREN"
    if rule_id == "#33":
        return "LBRACE"
    if rule_id == "#34":
        return "RBRACE"
    if rule_id == "#35":
        return "SEMICOLON"
    if rule_id == "#36":
        return "COMMA"
    if rule_id == "#37":
        raise( 'End of input' )
    return None


def tokenize(input_string):
    tokens = []
    pos = 0
    line = 1
    col = 1
    
    while pos < len(input_string):
        state = INITIAL_STATE
        last_accept_state = None
        last_accept_pos = -1
        current_pos = pos
        
        while current_pos < len(input_string):
            char = input_string[current_pos]
            if state in TRANSITIONS and char in TRANSITIONS[state]:
                state = TRANSITIONS[state][char]
                if state in ACCEPT_STATES:
                    last_accept_state = state
                    last_accept_pos = current_pos
                current_pos += 1
            else:
                break
                
        if last_accept_state is None:
            # Check for EOF rule when pos at end? The YALex handles EOF via specific rules if implemented.
            char = input_string[pos]
            print(f"LEXICAL ERROR at line {line}, col {col}: Unrecognized character '{char}'")
            return None
        
        # We matched something!
        lxm = input_string[pos : last_accept_pos + 1]
        rule_id = ACCEPT_STATES[last_accept_state]
        
        token = execute_action(rule_id, lxm)
        if token is not None:
            tokens.append(token)
            
        # Update line and column
        for c in lxm:
            if c == '\n':
                line += 1
                col = 1
            else:
                col += 1
                
        pos = last_accept_pos + 1
        
    # Process EOF
    state = INITIAL_STATE
    if state in TRANSITIONS and "eof" in TRANSITIONS[state]:
        state = TRANSITIONS[state]["eof"]
        if state in ACCEPT_STATES:
            execute_action(ACCEPT_STATES[state], "")
            
    return tokens

if __name__ == "__main__":
    import sys
    if len(sys.argv) > 1:
        with open(sys.argv[1], 'r') as f:
            content = f.read()
    else:
        content = sys.stdin.read()
        
    if content and not content.endswith('\n'):
        content += '\n'
        
    result = tokenize(content)
    if result:
        for t in result:
            print(t)
